18: // [#protodoc-title: Extension config discovery service (ECDS)]
19: // A service that supports dynamic configuration updates for a specific filter.
20: // Currently, ECDS is supported for network filters, HTTP filters, UDP session filters, and listener filters.
21: // Please check :ref:`Extension Config Discovery Service (ECDS) API <config_overview_extension_discovery>`.
22: //
23: // The overall extension config discovery service works as follows:
24: //
25: // #. A filter (:ref:`Downstream Network <envoy_v3_api_field_config.listener.v3.Filter.config_discovery>`,
26: //    :ref:`Upstream Network <envoy_v3_api_field_config.cluster.v3.Filter.config_discovery>`,
27: //    :ref:`Listener <envoy_v3_api_field_config.listener.v3.ListenerFilter.config_discovery>`,
28: //    :ref:`UDP Session <envoy_v3_api_field_extensions.filters.udp.udp_proxy.v3.UdpProxyConfig.SessionFilter.config_discovery>`,
29: //    or :ref:`HTTP <envoy_v3_api_field_extensions.filters.network.http_connection_manager.v3.HttpFilter.config_discovery>`)
30: //    contains a (:ref:`ExtensionConfigSource config discovery <envoy_v3_api_msg_config.core.v3.ExtensionConfigSource>`) configuration. This configuration
31: //    includes a :ref:`config_source <envoy_v3_api_field_config.core.v3.ExtensionConfigSource.config_source>`,
32: //    from which the filter configuration will be fetched.
33: // #. The client then registers for a resource using the filter name as the ``resource_name``.
34: // #. The xDS server sends back the filter's configuration.
35: // #. The client stores the configuration that will be used in the next instantiation of the filter chain,
36: //    i.e., for the next requests. Whenever an updated filter configuration arrives, it will be taken into
37: //    account in the following instantiation of the filter chain.
38: //
39: // .. note::
40: //   Filters that are configured using ECDS are warmed. For more details see
41: //   :ref:`ExtensionConfigSource <envoy_v3_api_msg_config.core.v3.ExtensionConfigSource>`.
42: 
43: // Return extension configurations.
44: service ExtensionConfigDiscoveryService {
45:   option (envoy.annotations.resource).type = "envoy.config.core.v3.TypedExtensionConfig";
46: 
47:   rpc StreamExtensionConfigs(stream discovery.v3.DiscoveryRequest)
48:       returns (stream discovery.v3.DiscoveryResponse) {
49:   }
50: 
51:   rpc DeltaExtensionConfigs(stream discovery.v3.DeltaDiscoveryRequest)
52:       returns (stream discovery.v3.DeltaDiscoveryResponse) {
53:   }
54: 
55:   rpc FetchExtensionConfigs(discovery.v3.DiscoveryRequest)
56:       returns (discovery.v3.DiscoveryResponse) {
57:     option (google.api.http).post = "/v3/discovery:extension_configs";
58:     option (google.api.http).body = "*";
59:   }
60: }
61: 
62: // [#not-implemented-hide:] Not configuration. Workaround c++ protobuf issue
63: // with importing services: https://github.com/google/protobuf/issues/4221 and
64: // protoxform to upgrade the file.
65: message EcdsDummy {
66: }
