3: package envoy.service.health.v3;
4: 
5: import "envoy/config/cluster/v3/cluster.proto";
6: import "envoy/config/core/v3/address.proto";
7: import "envoy/config/core/v3/base.proto";
8: import "envoy/config/core/v3/health_check.proto";
9: import "envoy/config/endpoint/v3/endpoint_components.proto";
10: 
11: import "google/api/annotations.proto";
12: import "google/protobuf/duration.proto";
13: 
14: import "envoy/annotations/deprecation.proto";
15: import "udpa/annotations/status.proto";
16: import "udpa/annotations/versioning.proto";
17: 
18: option java_package = "io.envoyproxy.envoy.service.health.v3";
19: option java_outer_classname = "HdsProto";
20: option java_multiple_files = true;
21: option go_package = "github.com/envoyproxy/go-control-plane/envoy/service/health/v3;healthv3";
22: option (udpa.annotations.file_status).package_version_status = ACTIVE;
23: 
24: // [#protodoc-title: Health discovery service (HDS)]
25: 
26: // HDS is Health Discovery Service. It compliments Envoy’s health checking
27: // service by designating this Envoy to be a healthchecker for a subset of hosts
28: // in the cluster. The status of these health checks will be reported to the
29: // management server, where it can be aggregated etc and redistributed back to
30: // Envoy through EDS.
31: service HealthDiscoveryService {
32:   // 1. Envoy starts up and if its can_healthcheck option in the static
33:   //    bootstrap config is enabled, sends HealthCheckRequest to the management
34:   //    server. It supplies its capabilities (which protocol it can health check
35:   //    with, what zone it resides in, etc.).
36:   // 2. In response to (1), the management server designates this Envoy as a
37:   //    healthchecker to health check a subset of all upstream hosts for a given
38:   //    cluster (for example upstream Host 1 and Host 2). It streams
39:   //    HealthCheckSpecifier messages with cluster related configuration for all
40:   //    clusters this Envoy is designated to health check. Subsequent
41:   //    HealthCheckSpecifier message will be sent on changes to:
42:   //    a. Endpoints to health checks
43:   //    b. Per cluster configuration change
44:   // 3. Envoy creates a health probe based on the HealthCheck config and sends
45:   //    it to endpoint(ip:port) of Host 1 and 2. Based on the HealthCheck
46:   //    configuration Envoy waits upon the arrival of the probe response and
47:   //    looks at the content of the response to decide whether the endpoint is
48:   //    healthy or not. If a response hasn't been received within the timeout
49:   //    interval, the endpoint health status is considered TIMEOUT.
50:   // 4. Envoy reports results back in an EndpointHealthResponse message.
51:   //    Envoy streams responses as often as the interval configured by the
52:   //    management server in HealthCheckSpecifier.
53:   // 5. The management Server collects health statuses for all endpoints in the
54:   //    cluster (for all clusters) and uses this information to construct
55:   //    EndpointDiscoveryResponse messages.
56:   // 6. Once Envoy has a list of upstream endpoints to send traffic to, it load
57:   //    balances traffic to them without additional health checking. It may
58:   //    use inline healthcheck (i.e. consider endpoint UNHEALTHY if connection
59:   //    failed to a particular endpoint to account for health status propagation
60:   //    delay between HDS and EDS).
61:   // By default, can_healthcheck is true. If can_healthcheck is false, Cluster
62:   // configuration may not contain HealthCheck message.
63:   // TODO(htuch): How is can_healthcheck communicated to CDS to ensure the above
64:   // invariant?
65:   // TODO(htuch): Add @amb67's diagram.
66:   rpc StreamHealthCheck(stream HealthCheckRequestOrEndpointHealthResponse)
67:       returns (stream HealthCheckSpecifier) {
68:   }
69: 
70:   // TODO(htuch): Unlike the gRPC version, there is no stream-based binding of
71:   // request/response. Should we add an identifier to the HealthCheckSpecifier
72:   // to bind with the response?
73:   rpc FetchHealthCheck(HealthCheckRequestOrEndpointHealthResponse) returns (HealthCheckSpecifier) {
74:     option (google.api.http).post = "/v3/discovery:health_check";
75:     option (google.api.http).body = "*";
76:   }
77: }
78: 
79: // Defines supported protocols etc, so the management server can assign proper
80: // endpoints to healthcheck.
81: message Capability {
82:   option (udpa.annotations.versioning).previous_message_type =
83:       "envoy.service.discovery.v2.Capability";
84: 
85:   // Different Envoy instances may have different capabilities (e.g. Redis)
86:   // and/or have ports enabled for different protocols.
87:   enum Protocol {
88:     HTTP = 0;
89:     TCP = 1;
90:     REDIS = 2;
91:   }
92: 
93:   repeated Protocol health_check_protocols = 1;
94: }
95: 
96: message HealthCheckRequest {
97:   option (udpa.annotations.versioning).previous_message_type =
98:       "envoy.service.discovery.v2.HealthCheckRequest";
99: 
100:   config.core.v3.Node node = 1;
101: 
102:   Capability capability = 2;
103: }
104: 
105: message EndpointHealth {
106:   option (udpa.annotations.versioning).previous_message_type =
107:       "envoy.service.discovery.v2.EndpointHealth";
108: 
109:   config.endpoint.v3.Endpoint endpoint = 1;
110: 
111:   config.core.v3.HealthStatus health_status = 2;
112: }
113: 
114: // Group endpoint health by locality under each cluster.
115: message LocalityEndpointsHealth {
116:   config.core.v3.Locality locality = 1;
117: 
118:   repeated EndpointHealth endpoints_health = 2;
119: }
120: 
121: // The health status of endpoints in a cluster. The cluster name and locality
122: // should match the corresponding fields in ClusterHealthCheck message.
123: message ClusterEndpointsHealth {
124:   string cluster_name = 1;
125: 
126:   repeated LocalityEndpointsHealth locality_endpoints_health = 2;
127: }
128: 
129: message EndpointHealthResponse {
130:   option (udpa.annotations.versioning).previous_message_type =
131:       "envoy.service.discovery.v2.EndpointHealthResponse";
132: 
133:   // Deprecated - Flat list of endpoint health information.
134:   repeated EndpointHealth endpoints_health = 1
135:       [deprecated = true, (envoy.annotations.deprecated_at_minor_version) = "3.0"];
136: 
137:   // Organize Endpoint health information by cluster.
138:   repeated ClusterEndpointsHealth cluster_endpoints_health = 2;
139: }
140: 
141: message HealthCheckRequestOrEndpointHealthResponse {
142:   option (udpa.annotations.versioning).previous_message_type =
143:       "envoy.service.discovery.v2.HealthCheckRequestOrEndpointHealthResponse";
144: 
145:   oneof request_type {
146:     HealthCheckRequest health_check_request = 1;
147: 
148:     EndpointHealthResponse endpoint_health_response = 2;
149:   }
150: }
151: 
152: message LocalityEndpoints {
153:   option (udpa.annotations.versioning).previous_message_type =
154:       "envoy.service.discovery.v2.LocalityEndpoints";
155: 
156:   config.core.v3.Locality locality = 1;
157: 
158:   repeated config.endpoint.v3.Endpoint endpoints = 2;
159: }
160: 
161: // The cluster name and locality is provided to Envoy for the endpoints that it
162: // health checks to support statistics reporting, logging and debugging by the
163: // Envoy instance (outside of HDS). For maximum usefulness, it should match the
164: // same cluster structure as that provided by EDS.
165: // [#next-free-field: 6]
166: message ClusterHealthCheck {
167:   option (udpa.annotations.versioning).previous_message_type =
168:       "envoy.service.discovery.v2.ClusterHealthCheck";
169: 
170:   string cluster_name = 1;
171: 
172:   repeated config.core.v3.HealthCheck health_checks = 2;
173: 
174:   repeated LocalityEndpoints locality_endpoints = 3;
175: 
176:   // Optional map that gets filtered by :ref:`health_checks.transport_socket_match_criteria <envoy_v3_api_field_config.core.v3.HealthCheck.transport_socket_match_criteria>`
177:   // on connection when health checking. For more details, see
178:   // :ref:`config.cluster.v3.Cluster.transport_socket_matches <envoy_v3_api_field_config.cluster.v3.Cluster.transport_socket_matches>`.
179:   repeated config.cluster.v3.Cluster.TransportSocketMatch transport_socket_matches = 4;
180: 
181:   // Optional configuration used to bind newly established upstream connections.
182:   // If the address and port are empty, no bind will be performed.
183:   config.core.v3.BindConfig upstream_bind_config = 5;
184: }
185: 
186: message HealthCheckSpecifier {
187:   option (udpa.annotations.versioning).previous_message_type =
188:       "envoy.service.discovery.v2.HealthCheckSpecifier";
189: 
190:   repeated ClusterHealthCheck cluster_health_checks = 1;
191: 
192:   // The default is 1 second.
193:   google.protobuf.Duration interval = 2;
194: }
195: 
196: // [#not-implemented-hide:] Not configuration. Workaround c++ protobuf issue with importing
197: // services: https://github.com/google/protobuf/issues/4221 and protoxform to upgrade the file.
198: message HdsDummy {
199: }
