3: package envoy.service.accesslog.v2;
4: 
5: import "envoy/api/v2/core/base.proto";
6: import "envoy/data/accesslog/v2/accesslog.proto";
7: 
8: import "udpa/annotations/status.proto";
9: import "validate/validate.proto";
10: 
11: option java_package = "io.envoyproxy.envoy.service.accesslog.v2";
12: option java_outer_classname = "AlsProto";
13: option java_multiple_files = true;
14: option go_package = "github.com/envoyproxy/go-control-plane/envoy/service/accesslog/v2;accesslogv2";
15: option (udpa.annotations.file_status).package_version_status = FROZEN;
16: 
17: // [#protodoc-title: gRPC Access Log Service (ALS)]
18: 
19: // Service for streaming access logs from Envoy to an access log server.
20: service AccessLogService {
21:   // Envoy will connect and send StreamAccessLogsMessage messages forever. It does not expect any
22:   // response to be sent as nothing would be done in the case of failure. The server should
23:   // disconnect if it expects Envoy to reconnect. In the future we may decide to add a different
24:   // API for "critical" access logs in which Envoy will buffer access logs for some period of time
25:   // until it gets an ACK so it could then retry. This API is designed for high throughput with the
26:   // expectation that it might be lossy.
27:   rpc StreamAccessLogs(stream StreamAccessLogsMessage) returns (StreamAccessLogsResponse) {
28:   }
29: }
30: 
31: // Empty response for the StreamAccessLogs API. Will never be sent. See below.
32: message StreamAccessLogsResponse {
33: }
34: 
35: // Stream message for the StreamAccessLogs API. Envoy will open a stream to the server and stream
36: // access logs without ever expecting a response.
37: message StreamAccessLogsMessage {
38:   message Identifier {
39:     // The node sending the access log messages over the stream.
40:     api.v2.core.Node node = 1 [(validate.rules).message = {required: true}];
41: 
42:     // The friendly name of the log configured in :ref:`CommonGrpcAccessLogConfig
43:     // <envoy_api_msg_config.accesslog.v2.CommonGrpcAccessLogConfig>`.
44:     string log_name = 2 [(validate.rules).string = {min_bytes: 1}];
45:   }
46: 
47:   // Wrapper for batches of HTTP access log entries.
48:   message HTTPAccessLogEntries {
49:     repeated data.accesslog.v2.HTTPAccessLogEntry log_entry = 1
50:         [(validate.rules).repeated = {min_items: 1}];
51:   }
52: 
53:   // Wrapper for batches of TCP access log entries.
54:   message TCPAccessLogEntries {
55:     repeated data.accesslog.v2.TCPAccessLogEntry log_entry = 1
56:         [(validate.rules).repeated = {min_items: 1}];
57:   }
58: 
59:   // Identifier data that will only be sent in the first message on the stream. This is effectively
60:   // structured metadata and is a performance optimization.
61:   Identifier identifier = 1;
62: 
63:   // Batches of log entries of a single type. Generally speaking, a given stream should only
64:   // ever include one type of log entry.
65:   oneof log_entries {
66:     option (validate.required) = true;
67: 
68:     HTTPAccessLogEntries http_logs = 2;
69: 
70:     TCPAccessLogEntries tcp_logs = 3;
71:   }
72: }
