3: package envoy.service.auth.v2;
4: 
5: import "envoy/api/v2/core/base.proto";
6: import "envoy/service/auth/v2/attribute_context.proto";
7: import "envoy/type/http_status.proto";
8: 
9: import "google/rpc/status.proto";
10: 
11: import "udpa/annotations/status.proto";
12: import "validate/validate.proto";
13: 
14: option java_package = "io.envoyproxy.envoy.service.auth.v2";
15: option java_outer_classname = "ExternalAuthProto";
16: option java_multiple_files = true;
17: option go_package = "github.com/envoyproxy/go-control-plane/envoy/service/auth/v2;authv2";
18: option (udpa.annotations.file_status).package_version_status = FROZEN;
19: 
20: // [#protodoc-title: Authorization Service ]
21: 
22: // The authorization service request messages used by external authorization :ref:`network filter
23: // <config_network_filters_ext_authz>` and :ref:`HTTP filter <config_http_filters_ext_authz>`.
24: 
25: // A generic interface for performing authorization check on incoming
26: // requests to a networked service.
27: service Authorization {
28:   // Performs authorization check based on the attributes associated with the
29:   // incoming request, and returns status `OK` or not `OK`.
30:   rpc Check(CheckRequest) returns (CheckResponse) {
31:   }
32: }
33: 
34: message CheckRequest {
35:   // The request attributes.
36:   AttributeContext attributes = 1;
37: }
38: 
39: // HTTP attributes for a denied response.
40: message DeniedHttpResponse {
41:   // This field allows the authorization service to send a HTTP response status
42:   // code to the downstream client other than 403 (Forbidden).
43:   type.HttpStatus status = 1 [(validate.rules).message = {required: true}];
44: 
45:   // This field allows the authorization service to send HTTP response headers
46:   // to the downstream client. Note that the `append` field in `HeaderValueOption` defaults to
47:   // false when used in this message.
48:   repeated api.v2.core.HeaderValueOption headers = 2;
49: 
50:   // This field allows the authorization service to send a response body data
51:   // to the downstream client.
52:   string body = 3;
53: }
54: 
55: // HTTP attributes for an ok response.
56: message OkHttpResponse {
57:   // HTTP entity headers in addition to the original request headers. This allows the authorization
58:   // service to append, to add or to override headers from the original request before
59:   // dispatching it to the upstream. Note that the `append` field in `HeaderValueOption` defaults to
60:   // false when used in this message. By setting the `append` field to `true`,
61:   // the filter will append the correspondent header value to the matched request header.
62:   // By leaving `append` as false, the filter will either add a new header, or override an existing
63:   // one if there is a match.
64:   repeated api.v2.core.HeaderValueOption headers = 2;
65: }
66: 
67: // Intended for gRPC and Network Authorization servers `only`.
68: message CheckResponse {
69:   // Status `OK` allows the request. Any other status indicates the request should be denied.
70:   google.rpc.Status status = 1;
71: 
72:   // An message that contains HTTP response attributes. This message is
73:   // used when the authorization service needs to send custom responses to the
74:   // downstream client or, to modify/add request headers being dispatched to the upstream.
75:   oneof http_response {
76:     // Supplies http attributes for a denied response.
77:     DeniedHttpResponse denied_response = 2;
78: 
79:     // Supplies http attributes for an ok response.
80:     OkHttpResponse ok_response = 3;
81:   }
82: }
