3: package envoy.service.ratelimit.v2;
4: 
5: import "envoy/api/v2/core/base.proto";
6: import "envoy/api/v2/ratelimit/ratelimit.proto";
7: 
8: import "udpa/annotations/migrate.proto";
9: import "udpa/annotations/status.proto";
10: 
11: option java_package = "io.envoyproxy.envoy.service.ratelimit.v2";
12: option java_outer_classname = "RlsProto";
13: option java_multiple_files = true;
14: option go_package = "github.com/envoyproxy/go-control-plane/envoy/service/ratelimit/v2;ratelimitv2";
15: option (udpa.annotations.file_status).package_version_status = FROZEN;
16: 
17: // [#protodoc-title: Rate Limit Service (RLS)]
18: 
19: service RateLimitService {
20:   // Determine whether rate limiting should take place.
21:   rpc ShouldRateLimit(RateLimitRequest) returns (RateLimitResponse) {
22:   }
23: }
24: 
25: // Main message for a rate limit request. The rate limit service is designed to be fully generic
26: // in the sense that it can operate on arbitrary hierarchical key/value pairs. The loaded
27: // configuration will parse the request and find the most specific limit to apply. In addition,
28: // a RateLimitRequest can contain multiple "descriptors" to limit on. When multiple descriptors
29: // are provided, the server will limit on *ALL* of them and return an OVER_LIMIT response if any
30: // of them are over limit. This enables more complex application level rate limiting scenarios
31: // if desired.
32: message RateLimitRequest {
33:   // All rate limit requests must specify a domain. This enables the configuration to be per
34:   // application without fear of overlap. E.g., "envoy".
35:   string domain = 1;
36: 
37:   // All rate limit requests must specify at least one RateLimitDescriptor. Each descriptor is
38:   // processed by the service (see below). If any of the descriptors are over limit, the entire
39:   // request is considered to be over limit.
40:   repeated api.v2.ratelimit.RateLimitDescriptor descriptors = 2;
41: 
42:   // Rate limit requests can optionally specify the number of hits a request adds to the matched
43:   // limit. If the value is not set in the message, a request increases the matched limit by 1.
44:   uint32 hits_addend = 3;
45: }
46: 
47: // A response from a ShouldRateLimit call.
48: message RateLimitResponse {
49:   enum Code {
50:     // The response code is not known.
51:     UNKNOWN = 0;
52: 
53:     // The response code to notify that the number of requests are under limit.
54:     OK = 1;
55: 
56:     // The response code to notify that the number of requests are over limit.
57:     OVER_LIMIT = 2;
58:   }
59: 
60:   // Defines an actual rate limit in terms of requests per unit of time and the unit itself.
61:   message RateLimit {
62:     enum Unit {
63:       // The time unit is not known.
64:       UNKNOWN = 0;
65: 
66:       // The time unit representing a second.
67:       SECOND = 1;
68: 
69:       // The time unit representing a minute.
70:       MINUTE = 2;
71: 
72:       // The time unit representing an hour.
73:       HOUR = 3;
74: 
75:       // The time unit representing a day.
76:       DAY = 4;
77:     }
78: 
79:     // A name or description of this limit.
80:     string name = 3;
81: 
82:     // The number of requests per unit of time.
83:     uint32 requests_per_unit = 1;
84: 
85:     // The unit of time.
86:     Unit unit = 2;
87:   }
88: 
89:   message DescriptorStatus {
90:     // The response code for an individual descriptor.
91:     Code code = 1;
92: 
93:     // The current limit as configured by the server. Useful for debugging, etc.
94:     RateLimit current_limit = 2;
95: 
96:     // The limit remaining in the current time unit.
97:     uint32 limit_remaining = 3;
98:   }
99: 
100:   // The overall response code which takes into account all of the descriptors that were passed
101:   // in the RateLimitRequest message.
102:   Code overall_code = 1;
103: 
104:   // A list of DescriptorStatus messages which matches the length of the descriptor list passed
105:   // in the RateLimitRequest. This can be used by the caller to determine which individual
106:   // descriptors failed and/or what the currently configured limits are for all of them.
107:   repeated DescriptorStatus statuses = 2;
108: 
109:   // A list of headers to add to the response
110:   repeated api.v2.core.HeaderValue headers = 3
111:       [(udpa.annotations.field_migrate).rename = "response_headers_to_add"];
112: 
113:   // A list of headers to add to the request when forwarded
114:   repeated api.v2.core.HeaderValue request_headers_to_add = 4;
115: }
